import { Check, Circle, Loader2, X } from 'lucide-react'
import { cn } from '#lib/utils'
import type { Objective } from '#lib/types'
import { Badge } from '#components/ui/badge'

export type ObjectiveStatus = 'pending' | 'current' | 'correct' | 'skipped'

interface Props {
  objectives: Objective[]
  statuses: ObjectiveStatus[]
  score: number
  total: number
}

export function ObjectiveTracker({ objectives, statuses, score, total }: Props) {
  return (
    <div className="space-y-4">
      <div className="rounded-2xl border border-border bg-card p-4">
        <div className="flex items-baseline justify-between">
          <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">Score</p>
          <p className="text-2xl font-bold tabular-nums">
            {score}
            <span className="text-base text-muted-foreground">/{total}</span>
          </p>
        </div>
        <div className="mt-2 h-1.5 w-full overflow-hidden rounded-full bg-secondary">
          <div
            className="h-full rounded-full bg-primary transition-all duration-500"
            style={{
              width: total === 0 ? '0%' : `${(score / total) * 100}%`
            }}
          />
        </div>
      </div>

      <div className="rounded-2xl border border-border bg-card p-4">
        <p className="mb-3 text-xs font-medium uppercase tracking-wide text-muted-foreground">Objectives</p>
        <ol className="space-y-1.5">
          {objectives.map((obj, i) => {
            const status = statuses[i] ?? 'pending'
            return (
              <li
                key={i}
                className={cn(
                  'flex items-start gap-2.5 rounded-lg px-2 py-1.5 text-sm transition-colors',
                  status === 'current' && 'bg-accent/60'
                )}
              >
                <span className="mt-0.5 shrink-0">
                  {status === 'correct' ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-success/15 text-success">
                      <Check className="size-3.5" />
                    </span>
                  ) : status === 'skipped' ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-danger/15 text-danger">
                      <X className="size-3.5" />
                    </span>
                  ) : status === 'current' ? (
                    <span className="flex size-5 items-center justify-center rounded-full bg-primary/15 text-primary">
                      <Loader2 className="size-3.5 animate-spin" />
                    </span>
                  ) : (
                    <Circle className="size-5 text-muted-foreground/50" />
                  )}
                </span>
                <div className="min-w-0 flex-1">
                  <p
                    className={cn(
                      'text-sm font-semibold leading-snug',
                      status === 'pending' && 'text-muted-foreground',
                      (status === 'correct' || status === 'skipped') &&
                        'text-muted-foreground line-through decoration-muted-foreground/40'
                    )}
                  >
                    {obj.topic}
                  </p>
                  <p
                    className={cn(
                      'mt-0.5 text-xs text-muted-foreground',
                      (status === 'correct' || status === 'skipped') && 'line-through decoration-muted-foreground/40'
                    )}
                  >
                    {obj.text}
                  </p>
                  <div className="mt-1 flex flex-wrap items-center gap-1">
                    <Badge variant="outline" className="text-xs font-normal">
                      {obj.question_count} question{obj.question_count === 1 ? '' : 's'}
                    </Badge>
                  </div>
                </div>
              </li>
            )
          })}
        </ol>
      </div>
    </div>
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { Loader2 } from 'lucide-react'
import { PlanCard } from '#components/plan-card'
import { MCQWidget } from '#components/mcq-widget'
import { ObjectiveTracker, type ObjectiveStatus } from '#components/objective-tracker'
import { SummaryView } from '#components/summary-view'
import { Card, CardContent } from '#components/ui/card'
import { Progress } from '#components/ui/progress'
import * as api from '#lib/api'
import type { AttemptSummary, Objective, Plan, QuizDTO } from '#lib/types'
import { difficultyLabel } from '#lib/helpers'

type Phase = 'loading' | 'review' | 'quiz' | 'summary' | 'error'

interface AnswerState {
  quizId: number
  learnerIndex: number | null
  attempts: number
  correct: boolean
  finalized: boolean
}

interface QuestionSlot {
  objectiveIndex: number
  questionIndex: number
  objective: Objective
}

function blankAnswer(quizId: number): AnswerState {
  return {
    quizId,
    learnerIndex: null,
    attempts: 0,
    correct: false,
    finalized: false
  }
}

function slotKey(objectiveIndex: number, questionIndex: number): string {
  return `${objectiveIndex}-${questionIndex}`
}

export function LessonPage() {
  const { planId } = useParams<{ planId: string }>()
  const navigate = useNavigate()
  const [phase, setPhase] = useState<Phase>('loading')
  const [plan, setPlan] = useState<Plan | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [quizzes, setQuizzes] = useState<Record<string, QuizDTO>>({})
  const [answers, setAnswers] = useState<Record<string, AnswerState>>({})
  const [currentIdx, setCurrentIdx] = useState(0)
  const [loadingQuiz, setLoadingQuiz] = useState(false)
  const [summary, setSummary] = useState<AttemptSummary | null>(null)
  const [finishing, setFinishing] = useState(false)

  const slots = useMemo<QuestionSlot[]>(() => {
    if (!plan) return []
    return plan.objectives.flatMap((objective, objectiveIndex) =>
      Array.from({ length: objective.question_count }, (_, questionIndex) => ({
        objectiveIndex,
        questionIndex,
        objective
      }))
    )
  }, [plan])

  useEffect(() => {
    if (!planId) return
    const id = Number(planId)

    async function loadPlan() {
      const p = await api.getPlan(id)
      setPlan(p)

      if (p.status === 'draft') {
        setPhase('review')
        return
      }

      if (p.status !== 'completed') {
        setPhase('quiz')
        return
      }

      try {
        const attempts = await api.listAttempts(id)
        if (attempts.length === 0) {
          setPhase('quiz')
          return
        }
        const latest = await api.getAttempt(attempts[0].id)
        setSummary(latest)
        setPhase('summary')
      } catch {
        setPhase('quiz')
      }
    }

    loadPlan().catch((err: unknown) => {
      setError((err as Error).message)
      setPhase('error')
    })
  }, [planId])

  // Preload cached quizzes when entering the quiz phase (retest path)
  useEffect(() => {
    if (phase !== 'quiz' || !planId || !plan) return
    const id = Number(planId)
    api
      .listQuizzes(id)
      .then((existing) => {
        if (existing.length === 0) return
        const map: Record<string, QuizDTO> = {}
        for (const q of existing) {
          map[slotKey(q.objectiveIndex, q.questionIndex)] = q
        }
        setQuizzes(map)
      })
      .catch(() => {
        // ignore — we'll lazy-generate
      })
  }, [phase, planId, plan])

  const currentSlot = slots[currentIdx]
  const currentKey = currentSlot ? slotKey(currentSlot.objectiveIndex, currentSlot.questionIndex) : ''
  const currentQuiz = quizzes[currentKey]

  // Lazy-generate the quiz for the current question when needed
  useEffect(() => {
    if (phase !== 'quiz' || !plan || !planId || !currentSlot) return
    if (currentQuiz || loadingQuiz) return
    const id = Number(planId)
    setLoadingQuiz(true)
    api
      .generateQuiz(id, currentSlot.objectiveIndex, currentSlot.questionIndex)
      .then((q) => {
        setQuizzes((prev) => ({ ...prev, [slotKey(q.objectiveIndex, q.questionIndex)]: q }))
      })
      .catch((err: unknown) => {
        setError((err as Error).message)
        setPhase('error')
      })
      .finally(() => setLoadingQuiz(false))
  }, [phase, plan, planId, currentSlot, currentQuiz, loadingQuiz])

  const handleApprove = useCallback(async () => {
    if (!plan) return
    try {
      const updated = await api.approvePlan(plan.id)
      setPlan(updated)
      setPhase('quiz')
    } catch (err) {
      setError((err as Error).message)
      setPhase('error')
    }
  }, [plan])

  const handleRevise = useCallback(
    async (feedback: string) => {
      if (!plan) return
      try {
        const updated = await api.revisePlan(plan.id, feedback)
        setPlan(updated)
        // Reset any quizzes cached from the previous draft.
        setQuizzes({})
        setAnswers({})
        setCurrentIdx(0)
      } catch (err) {
        setError((err as Error).message)
        setPhase('error')
      }
    },
    [plan]
  )

  const finish = useCallback(
    async (answersToSubmit?: Record<string, AnswerState>) => {
      if (!plan || !planId || finishing) return
      setFinishing(true)
      try {
        const payload = Object.values(answersToSubmit ?? answers).map((a) => ({
          quizId: a.quizId,
          learnerIndex: a.learnerIndex,
          attempts: a.attempts
        }))
        const result = await api.completeAttempt(plan.id, payload)
        setSummary(result)
        setPhase('summary')
      } catch (err) {
        setError((err as Error).message)
        setPhase('error')
      } finally {
        setFinishing(false)
      }
    },
    [plan, planId, answers, finishing]
  )

  const advance = useCallback(() => {
    if (!plan) return
    if (currentIdx + 1 >= slots.length) {
      void finish()
    } else {
      setCurrentIdx((i) => i + 1)
    }
  }, [currentIdx, plan, slots.length, finish])

  const handleIncorrect = useCallback(
    (key: string, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[key]?.id ?? -1
        const existing = prev[key] ?? blankAnswer(quizId)
        return {
          ...prev,
          [key]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: false,
            attempts: existing.attempts + 1,
            finalized: false
          }
        }
      })
    },
    [quizzes]
  )

  const handleCorrect = useCallback(
    (key: string, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[key]?.id ?? -1
        const existing = prev[key] ?? blankAnswer(quizId)
        return {
          ...prev,
          [key]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: true,
            // attempts stays — counts only incorrect tries
            finalized: true
          }
        }
      })
    },
    [quizzes]
  )

  const handleSkip = useCallback(
    (key: string) => {
      const quizId = quizzes[key]?.id ?? -1
      const existing = answers[key] ?? blankAnswer(quizId)
      const nextAnswers = {
        ...answers,
        [key]: {
          ...existing,
          quizId,
          learnerIndex: null,
          correct: false,
          finalized: true
        }
      }
      setAnswers(nextAnswers)
      if (currentIdx + 1 >= slots.length) {
        void finish(nextAnswers)
      } else {
        setCurrentIdx((i) => i + 1)
      }
    },
    [quizzes, answers, currentIdx, slots.length, finish]
  )

  const handleRetake = useCallback(() => {
    setAnswers({})
    setQuizzes({})
    setCurrentIdx(0)
    setSummary(null)
    setPhase('quiz')
  }, [])

  if (phase === 'loading') {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="size-6 animate-spin text-primary" />
      </div>
    )
  }

  if (phase === 'error' || !plan) {
    return (
      <div className="mx-auto max-w-2xl">
        <Card>
          <CardContent className="p-8 text-center">
            <p className="text-sm font-medium text-danger">{error ?? 'Something went wrong.'}</p>
          </CardContent>
        </Card>
      </div>
    )
  }

  if (phase === 'review') {
    return <PlanCard plan={plan} onApprove={handleApprove} onRevise={handleRevise} onBack={() => navigate('/')} />
  }

  if (phase === 'summary' && summary) {
    return <SummaryView summary={summary} onRetake={handleRetake} onBackToLibrary={() => navigate('/')} />
  }

  // quiz phase
  const total = slots.length
  const answerList = slots.map((slot) => answers[slotKey(slot.objectiveIndex, slot.questionIndex)])
  const completed = answerList.filter((a) => a?.finalized).length
  const score = answerList.filter((a) => a?.correct).length
  const progressPct = total === 0 ? 0 : Math.round((completed / total) * 100)

  const statuses: ObjectiveStatus[] = plan.objectives.map((obj, objectiveIndex) => {
    let correct = 0
    let finalized = 0
    for (let q = 0; q < obj.question_count; q++) {
      const a = answers[slotKey(objectiveIndex, q)]
      if (a?.finalized) finalized += 1
      if (a?.correct) correct += 1
    }
    if (finalized === 0) return 'pending'
    if (correct === obj.question_count) return 'correct'
    if (currentSlot?.objectiveIndex === objectiveIndex) return 'current'
    if (finalized === obj.question_count) return 'skipped'
    return 'current'
  })

  return (
    <div className="space-y-6">
      <div className="space-y-2">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <h1 className="truncate text-xl font-bold tracking-tight">{plan.title}</h1>
            <p className="text-xs text-muted-foreground">
              {difficultyLabel(plan.difficulty)} · {completed} of {total} questions done
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {score}
              <span className="text-base text-muted-foreground">/{total}</span>
            </p>
          </div>
        </div>
        <Progress value={progressPct} />
      </div>

      <div className="grid gap-6 lg:grid-cols-[1fr_280px]">
        <div className="min-w-0">
          {currentQuiz && currentSlot ? (
            <MCQWidget
              key={currentQuiz.id}
              quiz={currentQuiz}
              objectiveNumber={currentSlot.objectiveIndex + 1}
              totalObjectives={plan.objectives.length}
              questionNumber={currentSlot.questionIndex + 1}
              totalQuestionsInObjective={currentSlot.objective.question_count}
              onCorrect={(learnerIndex) => {
                handleCorrect(currentKey, learnerIndex)
              }}
              onIncorrect={(learnerIndex) => handleIncorrect(currentKey, learnerIndex)}
              onSkip={() => handleSkip(currentKey)}
              onNext={advance}
              isLast={currentIdx === total - 1}
            />
          ) : (
            <Card>
              <CardContent className="flex flex-col items-center justify-center gap-3 p-12 text-center">
                <Loader2 className="size-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  {currentSlot ? (
                    <>
                      Generating question {currentSlot.questionIndex + 1} for path {currentSlot.objectiveIndex + 1}...
                    </>
                  ) : (
                    <>Wrapping up...</>
                  )}
                </p>
              </CardContent>
            </Card>
          )}
          {finishing && (
            <p className="mt-4 flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              Building your progress report...
            </p>
          )}
        </div>

        <aside className="lg:sticky lg:top-20 lg:self-start">
          <ObjectiveTracker objectives={plan.objectives} statuses={statuses} score={score} total={total} />
        </aside>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import Markdown from 'react-markdown'
import { Check, CircleAlert, HelpCircle, Lightbulb, Loader2, MessageSquareText, Send, X } from 'lucide-react'
import { cn } from '#lib/utils'
import { Badge } from '#components/ui/badge'
import { Button } from '#components/ui/button'
import { Card, CardContent } from '#components/ui/card'
import { RadioGroup, RadioGroupItem } from '#components/ui/radio-group'
import { Textarea } from '#components/ui/textarea'
import { checkAnswer, getExplanation, getHint, learnMore } from '#lib/api'
import type { ChatMessage, QuizDTO } from '#lib/types'

interface Props {
  quiz: QuizDTO
  objectiveNumber: number
  totalObjectives: number
  questionNumber: number
  totalQuestionsInObjective: number
  onCorrect: (learnerIndex: number) => void
  onIncorrect: (learnerIndex: number) => void
  onSkip: () => void
  onNext: () => void
  isLast: boolean
}

type Status = 'idle' | 'submitted' | 'correct' | 'incorrect'

export function MCQWidget({
  quiz,
  objectiveNumber,
  totalObjectives,
  questionNumber,
  totalQuestionsInObjective,
  onCorrect,
  onIncorrect,
  onSkip,
  onNext,
  isLast
}: Props) {
  const [selected, setSelected] = useState<number | null>(null)
  const [status, setStatus] = useState<Status>('idle')
  const [submitting, setSubmitting] = useState(false)
  const [hint, setHint] = useState<string | null>(null)
  const [hintLoading, setHintLoading] = useState(false)
  const [explanation, setExplanation] = useState<string | null>(null)
  const [showExplanation, setShowExplanation] = useState(false)
  const [explanationLoading, setExplanationLoading] = useState(false)
  const [tries, setTries] = useState(0)
  const [chatOpen, setChatOpen] = useState(false)

  // Reset state when quiz changes (new objective)
  useEffect(() => {
    setSelected(null)
    setStatus('idle')
    setHint(null)
    setExplanation(null)
    setShowExplanation(false)
    setTries(0)
    setChatOpen(false)
  }, [quiz.id])

  const submit = async () => {
    if (selected === null || submitting) return
    setHint(null)
    setSubmitting(true)
    try {
      const res = await checkAnswer(quiz.id, selected)
      if (res.correct) {
        setStatus('correct')
        onCorrect(selected)
      } else {
        setStatus('incorrect')
        onIncorrect(selected)
        setTries((t) => t + 1)
      }
    } finally {
      setSubmitting(false)
    }
  }

  const retry = () => {
    setStatus('idle')
    setSelected(null)
    setHint(null)
  }

  const requestHint = async () => {
    setHintLoading(true)
    try {
      const res = await getHint(quiz.id, status === 'incorrect' ? selected : null)
      setHint(res.hint)
    } finally {
      setHintLoading(false)
    }
  }

  const locked = status === 'correct'

  return (
    <Card className="overflow-hidden">
      <CardContent className="p-0">
        <div className="border-b border-border bg-accent/40 px-5 py-3 sm:px-6">
          <div className="flex items-center justify-between gap-3">
            <div className="min-w-0">
              <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
                Path {objectiveNumber} of {totalObjectives} · Question {questionNumber} of {totalQuestionsInObjective}
              </p>
              <p className="mt-0.5 truncate text-sm font-semibold">{quiz.objectiveText}</p>
            </div>
            {tries > 0 && status !== 'correct' && (
              <Badge variant="destructive">
                {tries} {tries === 1 ? 'miss' : 'misses'}
              </Badge>
            )}
            {status === 'correct' && (
              <Badge variant="default">
                <Check className="size-3" />
                Correct
              </Badge>
            )}
          </div>
        </div>

        <div className="space-y-5 p-5 sm:p-6">
          <p className="text-base font-medium leading-relaxed">{quiz.question}</p>

          <RadioGroup
            value={selected !== null ? String(selected) : undefined}
            onValueChange={(v) => {
              if (locked) return
              const next = Number(v)
              setSelected(next)
              if (status === 'incorrect') {
                setStatus('idle')
                setHint(null)
              }
            }}
            className="gap-2.5"
          >
            {quiz.options.map((opt, i) => {
              const isSelected = selected === i
              const showAsCorrect = locked && isSelected
              const showAsWrong = status === 'incorrect' && isSelected
              return (
                <label
                  key={i}
                  className={cn(
                    'flex items-center gap-3 rounded-xl border p-3.5 text-sm transition-all',
                    locked ? 'cursor-default' : 'cursor-pointer',
                    !locked && 'hover:border-primary/50 hover:bg-accent/50',
                    isSelected && !locked ? 'border-primary bg-primary/5' : 'border-border bg-card',
                    showAsCorrect && 'border-success/60 bg-success/10 text-success',
                    showAsWrong && 'border-danger/60 bg-danger/10 text-danger'
                  )}
                >
                  <RadioGroupItem
                    value={String(i)}
                    disabled={locked}
                    className={cn(
                      showAsCorrect &&
                        'border-success text-success data-[checked]:bg-success data-[checked]:border-success',
                      showAsWrong && 'border-danger text-danger data-[checked]:bg-danger data-[checked]:border-danger'
                    )}
                  />
                  <span className="flex-1 leading-relaxed">{opt}</span>
                  {showAsCorrect && <Check className="size-4 shrink-0" />}
                  {showAsWrong && <X className="size-4 shrink-0" />}
                </label>
              )
            })}
          </RadioGroup>

          {status === 'incorrect' && (
            <div className="flex items-start gap-2.5 rounded-xl border border-danger/40 bg-danger/10 p-3.5 text-sm">
              <CircleAlert className="size-4 shrink-0 translate-y-0.5 text-danger" />
              <div>
                <p className="font-medium text-danger">Not quite.</p>
                <p className="mt-0.5 text-muted-foreground">
                  Try again — you can request a hint or ask for a deeper explanation. No penalty for retries.
                </p>
              </div>
            </div>
          )}

          {hint && (
            <div className="flex items-start gap-2.5 rounded-xl border border-primary/30 bg-primary/5 p-3.5 text-sm">
              <Lightbulb className="size-4 shrink-0 translate-y-0.5 text-primary" />
              <div>
                <p className="font-medium text-primary">Hint</p>
                <p className="mt-0.5 text-foreground">{hint}</p>
              </div>
            </div>
          )}

          {status === 'correct' && showExplanation && explanation && (
            <div className="flex items-start gap-2.5 rounded-xl border border-success/40 bg-success/10 p-3.5 text-sm">
              <Check className="size-4 shrink-0 translate-y-0.5 text-success" />
              <div>
                <p className="font-medium text-success">Explanation</p>
                <p className="mt-0.5 text-foreground">{explanation}</p>
              </div>
            </div>
          )}

          <div className="flex flex-wrap items-center gap-2 pt-1">
            {!locked && (
              <>
                <Button onClick={submit} disabled={selected === null || submitting} className="gap-1.5">
                  {submitting ? <Loader2 className="size-4 animate-spin" /> : <Send className="size-4" />}
                  {status === 'incorrect' ? 'Re-submit' : 'Submit answer'}
                </Button>
                <Button variant="outline" onClick={requestHint} disabled={hintLoading} className="gap-1.5">
                  {hintLoading ? <Loader2 className="size-4 animate-spin" /> : <HelpCircle className="size-4" />}
                  {hint ? 'New hint' : 'Get a hint'}
                </Button>
                <Button variant="ghost" onClick={() => setChatOpen(true)} className="gap-1.5">
                  <MessageSquareText className="size-4" />
                  AI Help
                </Button>
                {status === 'incorrect' && (
                  <Button variant="ghost" onClick={retry} className="ml-auto">
                    Reset selection
                  </Button>
                )}
                {status === 'incorrect' && tries >= 1 && (
                  <Button variant="ghost" onClick={onSkip} className="text-muted-foreground">
                    Skip →
                  </Button>
                )}
              </>
            )}
            {locked && (
              <>
                <Button
                  variant="outline"
                  onClick={async () => {
                    if (showExplanation) return
                    setExplanationLoading(true)
                    try {
                      const res = await getExplanation(quiz.id)
                      setExplanation(res.explanation)
                      setShowExplanation(true)
                    } finally {
                      setExplanationLoading(false)
                    }
                  }}
                  disabled={explanationLoading || showExplanation}
                  className="gap-1.5"
                >
                  {explanationLoading ? (
                    <Loader2 className="size-4 animate-spin" />
                  ) : (
                    'Show explanation'
                  )}
                </Button>
                <Button onClick={onNext} className="ml-auto gap-1.5">
                  {isLast ? 'Finish & see results' : 'Next'}
                </Button>
              </>
            )}
          </div>
        </div>
      </CardContent>

      {chatOpen && <LearnMorePanel quiz={quiz} onClose={() => setChatOpen(false)} />}
    </Card>
  )
}

interface LearnMoreProps {
  quiz: QuizDTO
  onClose: () => void
}

function LearnMorePanel({ quiz, onClose }: LearnMoreProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'assistant',
      content:
        'I can dig deeper into the topic behind this question — without revealing the answer. Ask me anything about the concepts.'
    }
  ])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)

  const send = async () => {
    const q = input.trim()
    if (!q || loading) return
    const nextHistory: ChatMessage[] = [...messages, { role: 'user', content: q }]
    setMessages(nextHistory)
    setInput('')
    setLoading(true)
    try {
      const res = await learnMore(
        quiz.id,
        q,
        nextHistory.filter((m) => m.role !== 'assistant' || m.content !== messages[0]?.content)
      )
      setMessages((cur) => [...cur, { role: 'assistant', content: res.message }])
    } catch (err) {
      setMessages((cur) => [
        ...cur,
        {
          role: 'assistant',
          content: `Sorry, I couldn't fetch an answer right now: ${(err as Error).message}`
        }
      ])
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-end sm:items-center sm:justify-end">
      <div className="absolute inset-0 bg-background/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative flex h-[70vh] w-full max-w-md flex-col rounded-t-2xl border border-border bg-card shadow-2xl sm:rounded-2xl">
        <div className="flex items-center justify-between border-b border-border bg-accent/40 px-4 py-3">
          <div className="flex items-center gap-2">
            <span className="flex size-8 items-center justify-center rounded-lg bg-primary text-primary-foreground">
              <MessageSquareText className="size-4" />
            </span>
            <div>
              <p className="text-sm font-semibold">Ask the tutor</p>
              <p className="text-xs text-muted-foreground">Answers stay grounded in your PDF</p>
            </div>
          </div>
          <Button variant="ghost" size="icon-sm" onClick={onClose}>
            <X className="size-4" />
          </Button>
        </div>
        <div className="flex-1 space-y-3 overflow-y-auto p-4">
          {messages.map((m, i) => (
            <div key={i} className={cn('flex', m.role === 'user' ? 'justify-end' : 'justify-start')}>
              <div
                className={cn(
                  'max-w-[85%] rounded-2xl px-3.5 py-2 text-sm leading-relaxed',
                  m.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-accent text-accent-foreground'
                )}
              >
                {m.role === 'user' ? (
                  <span className="whitespace-pre-wrap">{m.content}</span>
                ) : (
                  <Markdown>{m.content}</Markdown>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <Loader2 className="size-3 animate-spin" />
              Thinking...
            </div>
          )}
        </div>
        <div className="border-t border-border p-3">
          <div className="flex items-end gap-2">
            <Textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about the concept..."
              className="min-h-[44px] flex-1 resize-none"
              rows={1}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault()
                  void send()
                }
              }}
            />
            <Button onClick={send} disabled={loading || !input.trim()} size="icon">
              <Send className="size-4" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}

